using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service = new();

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    [TestClass]
    public sealed class CreateOrder
    {
        private readonly OrderService _service = new();

        [TestMethod]
        public void ReturnsOrder_WithCorrectCustomerId()
        {
            var items = CreateItems(("Widget", 10m, 2));

            var order = _service.CreateOrder("cust-1", items);

            Assert.AreEqual("cust-1", order.CustomerId);
        }

        [TestMethod]
        public void ReturnsOrder_WithCorrectItems()
        {
            var items = CreateItems(("Widget", 10m, 2));

            var order = _service.CreateOrder("cust-1", items);

            Assert.AreEqual(1, order.Items.Count);
            Assert.AreEqual("Widget", order.Items[0].ProductName);
        }

        [TestMethod]
        public void CalculatesTotal_FromItemPricesAndQuantities()
        {
            var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 3));

            var order = _service.CreateOrder("cust-1", items);

            Assert.AreEqual(35m, order.Total);
        }

        [TestMethod]
        public void AssignsNonEmptyId()
        {
            var items = CreateItems(("Widget", 10m, 1));

            var order = _service.CreateOrder("cust-1", items);

            Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        }

        [TestMethod]
        public void SetsCreatedAtToRecentUtcTime()
        {
            var before = DateTime.UtcNow;
            var items = CreateItems(("Widget", 10m, 1));

            var order = _service.CreateOrder("cust-1", items);

            Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
        }

        [TestMethod]
        public void ThrowsArgumentNullException_WhenCustomerIdIsNull()
        {
            var items = CreateItems(("Widget", 10m, 1));

            Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        }

        [TestMethod]
        public void ThrowsArgumentNullException_WhenItemsIsNull()
        {
            Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        }

        [TestMethod]
        public void ThrowsInvalidOperationException_WhenItemsListIsEmpty()
        {
            Assert.ThrowsExactly<InvalidOperationException>(() => _service.CreateOrder("cust-1", []));
        }
    }

    [TestClass]
    public sealed class GetOrder
    {
        private readonly OrderService _service = new();

        [TestMethod]
        public void ReturnsOrder_WhenOrderExists()
        {
            var items = CreateItems(("Widget", 10m, 1));
            var created = _service.CreateOrder("cust-1", items);

            var found = _service.GetOrder(created.Id);

            Assert.AreEqual(created.Id, found?.Id);
        }

        [TestMethod]
        public void ReturnsNull_WhenOrderDoesNotExist()
        {
            var result = _service.GetOrder("nonexistent");

            Assert.IsNull(result);
        }
    }

